    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Ingestion (TBs per day)",
        "items": [
          {
            "type": 12,
            "content": {
              "version": "NotebookGroup/1.0",
              "groupType": "editable",
              "items": [
                {
                  "type": 3,
                  "content": {
                    "version": "KqlItem/1.0",
                    "query": "Usage\n| where IsBillable == true\n| project TimeGenerated, DataType, Quantity\n| summarize IngestionVolumeinTB=sum(Quantity)/1048576 by bin(TimeGenerated, 1d), DataType",
                    "size": 2,
                    "timeContextFromParameter": "TimePicker",
                    "exportFieldName": "DataType",
                    "exportParameterName": "SelectedDataType",
                    "queryType": 0,
                    "resourceType": "microsoft.operationalinsights/workspaces",
                    "visualization": "barchart"
                  },
                  "name": "query - 2"
                },
                {
                  "type": 1,
                  "content": {
                    "json": "### Drill-Down: Daily Ingestion Detail\n\nClick a color segment in the chart above to filter details below. Use the **Export** button (↓) on the grid to download results as CSV.",
                    "style": "info"
                  },
                  "conditionalVisibility": {
                    "parameterName": "SelectedDataType",
                    "comparison": "isNotEqualTo",
                    "value": ""
                  },
                  "name": "text - drilldown-total-hint"
                },
                {
                  "type": 3,
                  "content": {
                    "version": "KqlItem/1.0",
                    "query": "let avgDaily = toscalar(Usage | where IsBillable == true | where DataType == '{SelectedDataType}' | summarize DailyGB = sum(Quantity)/1024 by bin(TimeGenerated, 1d) | summarize avg(DailyGB));\nUsage\n| where IsBillable == true\n| where DataType == '{SelectedDataType}'\n| summarize Ingestion_MB=round(sum(Quantity),2), Ingestion_GB=round(sum(Quantity)/1024,4), Ingestion_TB=round(sum(Quantity)/1048576,8), RecordCount=count() by bin(TimeGenerated, 1d), DataType, Solution\n| extend AvgDaily_GB=round(avgDaily,4), PctOfAvg=round(Ingestion_GB/iif(avgDaily==0,1.0,avgDaily)*100,1), SpikeStatus=iff(Ingestion_GB > avgDaily*2.0, 'CRITICAL SPIKE', iff(Ingestion_GB > avgDaily*1.5, 'ELEVATED', 'Normal'))\n| project TimeGenerated, DataType, Solution, Ingestion_MB, Ingestion_GB, Ingestion_TB, AvgDaily_GB, PctOfAvg, SpikeStatus, RecordCount\n| order by TimeGenerated desc",
                    "size": 1,
                    "title": "Spike Detail: {SelectedDataType} — Daily vs Average (export to CSV for cloud team)",
                    "timeContextFromParameter": "TimePicker",
                    "queryType": 0,
                    "resourceType": "microsoft.operationalinsights/workspaces",
                    "visualization": "table",
                    "gridSettings": {
                      "formatters": [
                        {
                          "columnMatch": "TimeGenerated",
                          "formatter": 6
                        },
                        {
                          "columnMatch": "Ingestion_MB",
                          "formatter": 4,
                          "formatOptions": {
                            "palette": "blue",
                            "showBorder": false
                          },
                          "numberFormat": {
                            "unit": 0,
                            "options": {
                              "style": "decimal",
                              "maximumFractionDigits": 2
                            }
                          }
                        },
                        {
                          "columnMatch": "Ingestion_GB",
                          "formatter": 4,
                          "formatOptions": {
                            "palette": "green",
                            "showBorder": false
                          },
                          "numberFormat": {
                            "unit": 0,
                            "options": {
                              "style": "decimal",
                              "maximumFractionDigits": 4
                            }
                          }
                        },
                        {
                          "columnMatch": "Ingestion_TB",
                          "formatter": 4,
                          "formatOptions": {
                            "palette": "orange",
                            "showBorder": false
                          },
                          "numberFormat": {
                            "unit": 0,
                            "options": {
                              "style": "decimal",
                              "maximumFractionDigits": 8
                            }
                          }
                        },
                        {
                          "columnMatch": "PctOfAvg",
                          "formatter": 4,
                          "formatOptions": {
                            "palette": "redGreen",
                            "showBorder": false
                          },
                          "numberFormat": {
                            "unit": 0,
                            "options": {
                              "style": "decimal",
                              "maximumFractionDigits": 1
                            }
                          }
                        },
                        {
                          "columnMatch": "SpikeStatus",
                          "formatter": 18,
                          "formatOptions": {
                            "thresholdsOptions": "colors",
                            "thresholdsGrid": [
                              {
                                "operator": "contains",
                                "thresholdValue": "CRITICAL",
                                "representation": "redBright",
                                "text": "{0}{1}"
                              },
                              {
                                "operator": "contains",
                                "thresholdValue": "ELEVATED",
                                "representation": "yellow",
                                "text": "{0}{1}"
                              },
                              {
                                "operator": "Default",
                                "thresholdValue": null,
                                "representation": "green",
                                "text": "{0}{1}"
                              }
                            ]
                          }
                        }
                      ],
                      "filter": true,
                      "sortBy": [
                        {
                          "itemKey": "TimeGenerated",
                          "sortOrder": 2
                        }
                      ],
                      "exportAllFields": true
                    }
                  },
                  "conditionalVisibility": {
                    "parameterName": "SelectedDataType",
                    "comparison": "isNotEqualTo",
                    "value": ""
                  },
                  "name": "query - drilldown-total"
                }
              ]
            },
            "conditionalVisibility": {
              "parameterName": "Tab",
              "comparison": "isEqualTo",
              "value": "First"
            },
            "name": "Ingestion (TBs per day)"
          }
        ]
      },
      "conditionalVisibility": {
        "parameterName": "Tab",
        "comparison": "isEqualTo",
        "value": "First"
      },
      "name": "Ingestion"
    },
    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Device Tables Breakout (GBs per day)",
        "items": [
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "Usage\r\n| project TimeGenerated, DataType, Quantity\r\n| where DataType in ('DeviceEvents', 'DeviceFileEvents', 'DeviceNetworkEvents','DeviceProcessEvents', 'DeviceImageLoadEvents', 'DeviceLogonEvents', 'DeviceNetworkInfo', 'DeviceRegistryEvents')\r\n| summarize IngestionVolumeGB=sum(Quantity)/1024 by bin(TimeGenerated, 1d), DataType\r\n",
              "size": 2,
              "timeContextFromParameter": "TimePicker",
              "exportFieldName": "DataType",
              "exportParameterName": "SelectedDataType",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "unstackedbar",
              "chartSettings": {
                "xSettings": {
                  "label": "Volume in GB"
                }
              }
            },
            "name": "query - 2"
          },
          {
            "type": 1,
            "content": {
              "json": "### Drill-Down: Device Table Ingestion Detail\n\nClick a bar segment above to populate per-day ingestion details below. Use the **Export** button on the grid to download as CSV.",
              "style": "info"
            },
            "conditionalVisibility": {
              "parameterName": "SelectedDataType",
              "comparison": "isNotEqualTo",
              "value": ""
