            "name": "text - drilldown-device-hint"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "Usage\n| where DataType == '{SelectedDataType}'\n| project TimeGenerated, DataType, Solution, Quantity_MB=Quantity, Quantity_GB=Quantity/1024, IsBillable\n| order by TimeGenerated desc",
              "size": 1,
              "title": "Detail: {SelectedDataType} — Daily Ingestion Breakdown",
              "timeContextFromParameter": "TimePicker",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "table",
              "gridSettings": {
                "formatters": [
                  {
                    "columnMatch": "TimeGenerated",
                    "formatter": 6
                  },
                  {
                    "columnMatch": "Quantity_MB",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "blue"
                    },
                    "numberFormat": {
                      "unit": 0,
                      "options": {
                        "style": "decimal",
                        "maximumFractionDigits": 2
                      }
                    }
                  },
                  {
                    "columnMatch": "Quantity_GB",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "green"
                    },
                    "numberFormat": {
                      "unit": 0,
                      "options": {
                        "style": "decimal",
                        "maximumFractionDigits": 4
                      }
                    }
                  }
                ],
                "filter": true,
                "sortBy": [
                  {
                    "itemKey": "TimeGenerated",
                    "sortOrder": 2
                  }
                ],
                "exportAllFields": true
              }
            },
            "conditionalVisibility": {
              "parameterName": "SelectedDataType",
              "comparison": "isNotEqualTo",
              "value": ""
            },
            "name": "query - drilldown-device"
          }
        ]
      },
      "conditionalVisibility": {
        "parameterName": "Tab",
        "comparison": "isEqualTo",
        "value": "Second"
      },
      "name": "Device Related Tables"
    },
    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Device File Events - Count",
        "items": [
          {
            "type": 1,
            "content": {
              "json": "Important! The count represented in the chart below does NOT include events from Microsoft, Google, or blank (no vendor).",
              "style": "warning"
            },
            "name": "text - 1"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "DeviceFileEvents\r\n| where InitiatingProcessVersionInfoCompanyName !startswith \"Microsoft\" and InitiatingProcessVersionInfoCompanyName != '' and InitiatingProcessVersionInfoCompanyName !startswith \"Google\"\r\n| summarize count() by InitiatingProcessVersionInfoCompanyName, bin(TimeGenerated, 1d)",
              "size": 2,
              "timeContextFromParameter": "TimePicker",
              "exportFieldName": "InitiatingProcessVersionInfoCompanyName",
              "exportParameterName": "SelectedVendor",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "chartSettings": {
                "createOtherGroup": 50
              },
              "visualization": "barchart"
            },
            "name": "query - 3"
          },
          {
            "type": 1,
            "content": {
              "json": "### Drill-Down: {SelectedVendor} — Device File Events\n\nClick a vendor color in the chart above. Detailed records appear below. Use the **Export** button to download as CSV.",
              "style": "info"
