            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "DeviceFileEvents\n| where InitiatingProcessVersionInfoCompanyName == '{SelectedVendor}'\n| project TimeGenerated, DeviceName, FileName, FolderPath, ActionType, InitiatingProcessFileName, InitiatingProcessCommandLine, InitiatingProcessVersionInfoCompanyName, InitiatingProcessVersionInfoProductName, InitiatingProcessVersionInfoFileVersion, InitiatingProcessAccountName, InitiatingProcessAccountDomain, SHA256\n| order by TimeGenerated desc",
              "size": 1,
              "title": "Detail: {SelectedVendor} — Device File Events",
              "timeContextFromParameter": "TimePicker",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
