              "query": "Usage\r\n| where IsBillable == true\r\n| where DataType !startswith \"Device\"\r\n| project TimeGenerated, DataType, Quantity\r\n| summarize IngestionVolumeinTB=sum(Quantity)/1048576 by bin(TimeGenerated, 1d), DataType",
